#include <bits/stdc++.h>
using namespace std;
const int N=1003,M=10004;
struct Edge{
    int u,v,w;
}edge[M];
int n,m,k,f[N],ans;
bool cmp(Edge x,Edge y){
    return x.w<y.w;
}
int father(int x){
	return (f[x]==x?x:f[x]=father(f[x]));
}
int main(){
    scanf("%d%d%d",&n,&m,&k);
    k=n-k;
    for(int i=1;i<=n;i++)
    	f[i]=i;
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
    sort(edge+1,edge+m+1,cmp);
    for(int i=1;i<=m && k;i++){
        int fu=father(edge[i].u),fv=father(edge[i].v);
    	if(fu!=fv)
    		f[fv]=fu,ans+=edge[i].w,k--;
    }
    if(k)
    	printf("No Answer");
    else
    	printf("%d",ans);
    return 0;
}
